import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:30。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "閉館了。行政組開始拆展。牆上的百年校史展板被一片片卸下來，螺絲掉進鐵盤裡的聲音在空曠的展廳裡很響。玻璃展櫃被推到牆邊，用防塵布蓋住。雨打在高窗上，聲音比白天更密。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言和許星棠在校史館側門外。隔著半開的玻璃門，能看見展廳裡面。他們沒有進去。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任在。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）比前幾輪更早。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "展廳中央。時間膠囊展示基座。底座是木製的，外面罩著一層深色保護漆，正面嵌著銅質校徽。基座上方原本放著時間膠囊的透明壓克力罩，已經被行政組搬走了。底座裸露著。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任蹲在基座旁邊。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有站著指揮。他蹲下來了。手裡拿著一支筆型手電筒，照著基座底板的下方。深灰色西裝外套的下擺拖在地上，他沒有注意到。金屬細框眼鏡滑到鼻樑中間，他沒有推。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在看底板。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前幾輪，林主任在這個時間點都在禮堂側台盯流程。他不會親自來校史館。他會派行政組來拆。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪——他來了。他親自蹲在基座旁邊。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為我告訴他，左側暗槽裡可能有密碼提示。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個工作人員站在林主任身後。一個手裡拿著扳手，一個手裡拿著工具箱。他們在等。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "拿扳手的那個彎下腰，看了看林主任手電筒照的方向。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "主任，是整個底板都拆嗎？", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音不大，但在空展廳裡很清楚。顧言隔著玻璃門聽見了每一個字。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任沒有立刻回答。他把手電筒關了。站起來。用手背擦了一下額頭——不是因為熱，展廳裡的冷氣還在運轉。是因為額頭上有汗。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "左側先看。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "其他別動。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他壓低了聲音。但壓不住手在抖。他的左手插在西裝褲口袋裡，口袋的布料被攥出一個棱角。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）左側。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他說了「左側」。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我告訴他的是「基座底板左側暗槽裡可能有我爸留下的密碼提示」。他記住了「左側」。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯命中了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠站在顧言旁邊。她的相機已經舉起來了。鏡頭對著展廳裡面。快門聲很輕——她把驅動模式調成了靜音。但顧言能聽見她的呼吸變了。變慢了。像在等一個更清楚的畫面。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她連拍了五張。林主任蹲在基座旁邊的姿勢。手電筒的光。工作人員站在後面等。底座裸露的木紋。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "拍到了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他蹲在底板旁邊。手電筒照的方向是左側。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不急。先看完整。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任站起來之後，沒有離開基座。他繞到基座後方，用手指摸了一遍底板的邊緣。動作很快，像在找什麼東西的接縫。然後他停住了。他的手指卡在底板左側的一個位置上，不動了。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他找到了暗槽的位置。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他沒有打開。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任站直了。他把手電筒收進西裝內袋。轉身面向工作人員。他的嘴唇動了幾下——顧言隔著玻璃聽不太清。但他讀出了幾個字。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「⋯⋯先封起來。⋯⋯別讓人碰。」", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "工作人員點頭。拿工具箱的那個從箱子裡拿出一卷警戒帶。黃色的。他開始在基座周圍拉線。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在封鎖基座。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是拆。是封。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不對。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他的反應不對。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠在門框上。雨從門縫裡吹進來，打在他的袖口上。他沒有感覺。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果林主任是主謀——如果他自己就知道暗槽裡有什麼——他不需要蹲下來用手電筒找。他直接讓人拆開就好。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他蹲了。他找了。他找到了位置，然後——沒有打開。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他封起來了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這不是「我要拿到裡面的東西」。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是「我不能讓別人拿到裡面的東西」。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他在補。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在堵。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他像一個人聽說哪裡可能有漏洞，趕過去先把洞堵上。不是像一個設計了整個局的人。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任拉出手機。撥號。他走到展廳角落，背對著工作人員。聲音壓得更低了。顧言隔著玻璃門只聽見碎片。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「⋯⋯左側⋯⋯有暗槽⋯⋯不是相機⋯⋯是密碼⋯⋯」", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在打電話。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在回報。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯回報給誰？", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果他是最高權限，他不需要回報。他自己決定就好。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他在打電話。他在跟上面的人說。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）記下來。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任線命中。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他對基座左側有反應。他封鎖了。他打電話回報了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但——", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這條線可能會回到上面。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不能只看他。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠放下相機。她沒有說話。她看著顧言的側臉——他的表情沒有變，但他的眼睛在動。像在讀一本只有他看得見的筆記。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他的反應。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不像在拿東西。像在藏東西。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她也看出來了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任的反應是補救。是封堵。不是設計全局的人會有的反應。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他怕基座。他怕裡面的東西被別人找到。但他自己不確定裡面到底有什麼。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在聽命。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "展廳裡，工作人員拉完了警戒帶。基座被黃色封條圍起來了。在空曠的展廳中央，像一個被隔離的證物。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任收起手機。他推了推眼鏡。整理了一下西裝下擺——上面沾了灰。他拍了兩下。然後他走向展廳出口。步伐比正常快半拍。像永遠在趕路。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭看基座。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他走了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）去見電話那頭的人。或者去處理下一件事。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯第一條線。命中。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但不是終點。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠把相機收回胸前。她低頭看了一眼螢幕——最後一張照片。林主任蹲在基座旁邊。手電筒的光打在底板下方。他的手指按在左側邊緣。額頭上有汗。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "夠了嗎。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不夠。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這只證明林主任怕基座。不證明他能開22:58那道門。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他是手。手會動。但手背後有人在指。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）下一條線。20:40。鐘樓。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）看韓越那條有沒有反應。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們從側門退開。雨從廊頂的浪板縫裡漏下來，走廊上全是濕的。腳步聲被雨蓋住。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館的燈滅了一半。展廳裡只剩下基座旁邊的應急燈。黃色的警戒帶在冷光裡很亮。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任已經不在了。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他的汗還在玻璃門的指紋裡。他的手電筒光還在顧言的視網膜上。他的「左側」還在顧言的耳朵裡。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一條假鑰匙。放進林主任的口袋。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他動了。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他動的方式——是去堵，不是去拿。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這說明他上面還有人。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯那個人是誰。", background: Background.Chapter_7_Ch7_Act9_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館在身後暗下去。基座留在黑暗裡，被黃色封條圍著，像一個不敢被打開的秘密。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言和許星棠走進雨裡。往主樓方向。往下一個時間點。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:40。鐘樓。", background: Background.Chapter_7_Ch7_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二條線。", background: Background.Chapter_7_Ch7_Act9_S0 },
];
